Animals::Animals(char* nm, int ag) // c'tor
{
	size_t len = strlen(nm);
	name = new char[len+1];
	strcpy(name, nm);
	age = ag;
}

Animals::~Animals() // d'tor
{
	age=0;
	free(name);
	name = NULL;
}

Animals::Animals(const Animals& other) // copy c'tor
{
	size_t len = strlen(other.name);
	name = new char[len+1];
	strcpy(name, other.name);
	age = other.age;
}

void Animals::Print()
